function candidate(first, second, options) {
  if (!second) {
    return first;
  }

  var owns = Object.prototype.hasOwnProperty;
  var arrays = Array.isArray;
  var allowProtected = !!(options && (options.plainObjects || options.allowPrototypes || options.allowPrototypeProperties || options.allowUnsafeKeys));

  function objectLike(value) {
    return value !== null && typeof value === 'object';
  }

  function keyAllowed(key) {
    return allowProtected || !owns.call(Object.prototype, key);
  }

  function makeRecord() {
    return options && options.plainObjects ? Object.create(null) : {};
  }

  function join(left, right) {
    if (!right) {
      return left;
    }

    if (!objectLike(right)) {
      if (arrays(left)) {
        left.push(right);
        return left;
      }
      if (left && typeof left === 'object') {
        var label = String(right);
        if (keyAllowed(label)) {
          left[label] = true;
        }
        return left;
      }
      return [left, right];
    }

    if (!objectLike(left)) {
      return arrays(right) ? [left].concat(right) : [left, right];
    }

    if (arrays(left) && arrays(right)) {
      for (var i = 0; i < right.length; i += 1) {
        if (!owns.call(right, i)) {
          continue;
        }
        if (owns.call(left, i)) {
          if (objectLike(left[i]) && objectLike(right[i])) {
            left[i] = join(left[i], right[i]);
          } else {
            left.push(right[i]);
          }
        } else {
          left[i] = right[i];
        }
      }
      return left;
    }

    var base = left;
    if (arrays(left) && !arrays(right)) {
      base = makeRecord();
      for (var j = 0; j < left.length; j += 1) {
        if (owns.call(left, j)) {
          base[j] = left[j];
        }
      }
    }

    var names = Object.keys(right);
    for (var k = 0; k < names.length; k += 1) {
      var name = names[k];
      if (owns.call(base, name)) {
        base[name] = join(base[name], right[name]);
      } else {
        base[name] = right[name];
      }
    }
    return base;
  }

  return join(first, second);
}
